SELECT COUNT(app_id) AS installed_app_count
FROM device_applications
WHERE device_id = '1';

SELECT COUNT(device_id) 
FROM device_applications 
WHERE app_id = 1;

SELECT app_id
FROM device_applications
WHERE device_id = '0';

SELECT COUNT(app_id) AS app_count
FROM device_applications
WHERE device_id = '0';

SELECT COUNT(device_id) AS device_count
FROM user_devices
WHERE user_id = 0;
